const { exec } = require('child_process');
const path = require('path');
const fs = require('fs').promises;
const crypto = require('crypto');

const ALLOWED_INPUT_EXTENSIONS = ['.doc', '.docx', '.odt', '.rtf', '.txt', '.xls', '.xlsx', '.ods', '.ppt', '.pptx', '.odp'];
const ALLOWED_OUTPUT_FORMATS = ['pdf', 'docx', 'odt', 'html', 'txt', 'xlsx', 'ods', 'pptx', 'odp'];
const MAX_FILENAME_LENGTH = 255;
const CONVERSION_TIMEOUT = 60000;
const TEMP_DIR = process.env.TEMP || '/tmp';

function sanitizeFilename(filename) {
    if (!filename || typeof filename !== 'string') {
        throw new Error('Invalid filename');
    }
    
    const basename = path.basename(filename);
    
    if (basename.length > MAX_FILENAME_LENGTH) {
        throw new Error('Filename too long');
    }
    
    if (basename !== filename || filename.includes('..') || filename.includes('/') || filename.includes('\\')) {
        throw new Error('Invalid filename: path traversal detected');
    }
    
    const sanitized = basename.replace(/[^a-zA-Z0-9._-]/g, '_');
    
    if (sanitized !== basename) {
        throw new Error('Invalid characters in filename');
    }
    
    return sanitized;
}

function validateOutputFormat(format) {
    if (!format || typeof format !== 'string') {
        throw new Error('Invalid output format');
    }
    
    const sanitizedFormat = format.toLowerCase().replace(/[^a-z]/g, '');
    
    if (!ALLOWED_OUTPUT_FORMATS.includes(sanitizedFormat)) {
        throw new Error('Output format not allowed');
    }
    
    return sanitizedFormat;
}

function validateInputExtension(filename) {
    const ext = path.extname(filename).toLowerCase();
    
    if (!ALLOWED_INPUT_EXTENSIONS.includes(ext)) {
        throw new Error('Input file extension not allowed');
    }
    
    return true;
}

async function cleanupFiles(files) {
    for (const file of files) {
        try {
            await fs.unlink(file);
        } catch (err) {
            console.error(`Failed to cleanup file ${file}:`, err.message);
        }
    }
}

function executeLibreOffice(inputPath, outputDir, outputFormat) {
    return new Promise((resolve, reject) => {
        const args = [
            '--headless',
            '--invisible',
            '--nodefault',
            '--nofirststartwizard',
            '--nolockcheck',
            '--nologo',
            '--norestore',
            '--convert-to',
            outputFormat,
            '--outdir',
            outputDir,
            inputPath
        ];
        
        const command = 'soffice';
        const fullCommand = `${command} ${args.map(arg => {
            if (arg.includes(' ') || arg.includes('"') || arg.includes("'")) {
                return `"${arg.replace(/"/g, '\\"')}"`;
            }
            return arg;
        }).join(' ')}`;
        
        const execOptions = {
            timeout: CONVERSION_TIMEOUT,
            maxBuffer: 10 * 1024 * 1024,
            env: {
                HOME: TEMP_DIR,
                PATH: process.env.PATH
            },
            shell: false
        };
        
        exec(fullCommand, execOptions, (error, stdout, stderr) => {
            if (error) {
                if (error.killed) {
                    reject(new Error('Conversion timeout exceeded'));
                } else {
                    reject(new Error(`Conversion failed: ${error.message}`));
                }
                return;
            }
            
            resolve({ stdout, stderr });
        });
    });
}

module.exports = async function (context, req) {
    const filesToCleanup = [];
    
    try {
        if (!req.body || !req.body.filename || !req.body.outputFormat) {
            context.res = {
                status: 400,
                body: { error: 'Missing required parameters: filename and outputFormat' }
            };
            return;
        }
        
        const sanitizedFilename = sanitizeFilename(req.body.filename);
        const outputFormat = validateOutputFormat(req.body.outputFormat);
        
        validateInputExtension(sanitizedFilename);
        
        const sessionId = crypto.randomBytes(16).toString('hex');
        const workDir = path.join(TEMP_DIR, `conversion_${sessionId}`);
        await fs.mkdir(workDir, { recursive: true, mode: 0o700 });
        
        const inputPath = path.join(workDir, sanitizedFilename);
        filesToCleanup.push(inputPath);
        
        if (req.body.fileContent) {
            const buffer = Buffer.from(req.body.fileContent, 'base64');
            
            if (buffer.length > 50 * 1024 * 1024) {
                throw new Error('File size exceeds maximum allowed (50MB)');
            }
            
            await fs.writeFile(inputPath, buffer, { mode: 0o600 });
        } else {
            throw new Error('File content is required');
        }
        
        await executeLibreOffice(inputPath, workDir, outputFormat);
        
        const baseName = path.parse(sanitizedFilename).name;
        const outputFilename = `${baseName}.${outputFormat}`;
        const outputPath = path.join(workDir, outputFilename);
        filesToCleanup.push(outputPath);
        
        let outputExists = false;
        try {
            await fs.access(outputPath);
            outputExists = true;
        } catch (err) {
            outputExists = false;
        }
        
        if (!outputExists) {
            throw new Error('Conversion completed but output file not found');
        }
        
        const outputBuffer = await fs.readFile(outputPath);
        const outputBase64 = outputBuffer.toString('base64');
        
        context.res = {
            status: 200,
            headers: {
                'Content-Type': 'application/json'
            },
            body: {
                success: true,
                filename: outputFilename,
                fileContent: outputBase64,
                size: outputBuffer.length
            }
        };
        
    } catch (error) {
        context.log.error('Conversion error:', error);
        
        context.res = {
            status: error.message.includes('not allowed') || error.message.includes('Invalid') ? 400 : 500,
            body: {
                error: error.message
            }
        };
    } finally {
        await cleanupFiles(filesToCleanup);
    }
};